import fsExtra from 'https://esm.sh/fs-extra';
try {
  const file = '/tmp/harness-fs-extra.txt';
  await fsExtra.outputFile(file, 'ok');
  const content = await fsExtra.readFile(file, 'utf8');
  if (content !== 'ok') throw new Error('content mismatch');
  console.log('PASS');
} catch (e) {
  console.error(e.message);
  process.exit(1);
}

import esbuild from 'https://esm.sh/esbuild';
try {
  const result = await esbuild.transform('let x = 1;', { loader: 'js' });
  if (typeof result.code !== 'string') throw new Error('transform failed');
  console.log('PASS');
} catch (e) {
  console.error(e.message);
  process.exit(1);
